  }

  const getStyleForLevel = (level: number) => {
    switch (level) {
      case 0: return 'bg-black text-white font-bold border-b border-white';
      case 1: return 'bg-red-500 text-white font-bold';
      case 2: return 'bg-orange-400 text-black font-semibold shadow-sm';
      case 3: return 'bg-cyan-200 text-black border border-cyan-300';
      case 4: return 'bg-green-100 text-black border border-green-200';
      default: return 'bg-gray-100 text-slate-600';
    }
  };

  const renderTaggedContent = (content: string) => {
      // Handle footnotes inside content
      const parts = content.split(/({{footnotenumber\s*\d+}}.*?{{-footnotenumber\s*\d+}})/g);
      return parts.map((part, i) => {
        if (part.match(/^{{footnotenumber\s*\d+}}/)) {
