                        FILE: {line.match(/FILE_START: (.*?) >>>>/)?.[1] || 'DOC'}
                    </div>
                </div>
            );
        }

        // --- IMPROVED PARSER: Handle Inline text_level and levelN ---
        // Match: {{tag}}Content{{-tag}}
        const blockMatch = line.match(/{{(text_level|level\s*\d+)}}([\s\S]*?){{-(text_level|level\s*\d+)}}/);

        if (blockMatch) {
            const tagName = blockMatch[1].trim();
            const content = blockMatch[2];

            if (tagName === 'text_level') {
                return (
                    <div key={idx} className="my-1 p-3 bg-yellow-50/50 border-l-4 border-yellow-200 text-slate-700 leading-relaxed shadow-sm rounded-r">
                        {renderTaggedContent(content)}
                    </div>
                );
            } else if (tagName.startsWith('level')) {
                const level = parseInt(tagName.replace('level', '')) || 0;
                return (
                    <div key={idx} className="my-2 flex items-start gap-2">
                        <span className="bg-slate-200 text-slate-500 text-[9px] font-bold px-1 py-0.5 rounded mt-1 shrink-0">L{level}</span>
                        <div className={`${getStyleForLevel(level)} px-3 py-1 rounded-sm font-medium shadow-sm inline-block`}>
                            {renderTaggedContent(content)}
                        </div>
                    </div>
                );
            }
        }

        // --- Handle footnote blocks ---
        const footnoteMatch = line.match(/{{footnote\s*(\d+)}}([\s\S]*?){{-footnote\s*\d+}}/);
