                  <div className="bg-indigo-50 px-4 py-2 text-xs font-bold text-indigo-600 border-b border-indigo-100 uppercase">Verification</div>
                  <div className="flex-1 overflow-auto p-4 font-mono text-sm leading-relaxed">
                      {renderLines(translatedText)}
                  </div>
              </div>
          </div>
      );
  }

  return (
    <div className="font-mono text-sm bg-white p-6 rounded-lg overflow-auto max-h-[750px] border border-slate-300 shadow-inner leading-relaxed">
      {renderLines(text)}
    </div>
  );
};

export default ResultViewer;

