export const PROMPT_STEP_2 = (previousContext: string, language: string = 'AUTO') => `
You are a "Structural Micro-Architect".
**GOAL:** Wrap 100% of the text into a hierarchical component structure. 

**CRITICAL RULE: NO NAKED TEXT**
- Every single character must be inside a tag. 
- Content blocks (paragraphs, bullets, lists) MUST be wrapped in {{text_level}}...{{-text_level}}.
- INSIDE the {{text_level}}, every individual item MUST be wrapped in {{levelN}}...{{-levelN}}.

**TAG SPELLING CHECK:**
- Correct: {{text_level}} / {{-text_level}}
- Prohibited: {{text_leve}}, {{text-level}}, {{text_level }}

**STRUCTURAL TEMPLATE:**
{{level1}}Headline Text{{-level1}}
{{text_level}}
{{level2}}Paragraph content 1...{{-level2}}
{{level2}}Paragraph content 2...{{-level2}}
{{-text_level}}

**ALGORITHM:**
1. **PRESERVE** headlines from Step 3.
2. **GROUP** all lines between headlines into one {{text_level}} block.
3. **ATOMIZE:** Inside that block, wrap every line/paragraph into a {{levelN}} tag.
   - Use Level (Headline Level + 1) for normal paragraphs.
   - Use Level (Headline Level + 2) for sub-bullets.
4. **FOOTNOTES:** Footnotes ({{footnoteN}}) are independent. Do NOT wrap them in {{text_level}} and do NOT put {{levelN}} inside them.

**CONTEXT:**
Previous chunk context: "...${previousContext.slice(-150).replace(/\n/g, ' ')}..."

**OUTPUT:**
Full text, 100% tagged. No text allowed outside of {{levelN}}, {{text_level}}, or {{footnoteN}}.
`;

import React, { useState, useEffect } from 'react';

interface ResultViewerProps {
  text: string;
  translatedText?: string;
  isEditing: boolean;
  onTextChange: (newText: string) => void;
}

const ResultViewer: React.FC<ResultViewerProps> = ({ text, translatedText, isEditing, onTextChange }) => {
  const [localText, setLocalText] = useState(text);

  useEffect(() => {
    if (isEditing) setLocalText(text);
  }, [isEditing, text]);

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newVal = e.target.value;
    setLocalText(newVal);
    onTextChange(newVal);
  };

  if (!text && !isEditing) return <div className="text-gray-400 italic p-4">Waiting for results...</div>;

  if (isEditing) {
    return (
      <div className="w-full">
        <div className="bg-yellow-50 border-b border-yellow-200 px-4 py-2 text-xs text-yellow-800 font-bold flex justify-between items-center">
             <span>EDIT MODE</span>
             <span className="font-normal opacity-75 italic">Ensure every block has level tags</span>
        </div>
        <textarea
          className="w-full h-[650px] p-6 font-mono text-sm bg-white border border-slate-300 rounded-b-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 leading-relaxed resize-none"
          value={localText}
          onChange={handleChange}
          spellCheck={false}
        />
      </div>
    );
  }

  const getStyleForLevel = (level: number) => {
    switch (level) {
      case 0: return 'bg-black text-white font-bold border-b border-white';
      case 1: return 'bg-red-600 text-white font-bold';
      case 2: return 'bg-orange-400 text-black font-semibold';
      case 3: return 'bg-cyan-100 text-cyan-900 border-l-4 border-cyan-400';
      case 4: return 'bg-green-50 text-green-900 border-l-4 border-green-400';
      default: return 'bg-slate-50 text-slate-600 border-l-4 border-slate-300';
    }
  };

  const renderContentWithFootnotes = (content: string) => {
    const parts = content.split(/({{footnotenumber\s*\d+}}.*?{{-footnotenumber\s*\d+}})/g);
    return parts.map((part, i) => {
      if (part.match(/^{{footnotenumber/)) {
        return (
          <span key={i} className="inline-flex items-center justify-center bg-purple-600 text-white w-4 h-4 rounded-full text-[9px] font-bold mx-0.5 align-top shadow-sm" title={part}>
            {part.replace(/\D/g, '')}
          </span>
        );
      }
      return part;
    });
  };

  const parseBlocks = (raw: string) => {
    // Regex to split into: File Markers, text_level blocks, standalone levelN (headlines), and footnotes
    const blockRegex = /(<<<< FILE_START:.*? >>>>)|({{text_level}}[\s\S]*?{{-text_level}})|({{level\s*\d+}}[\s\S]*?{{-level\s*\d+}})|({{footnote\s*\d+}}[\s\S]*?{{-footnote\s*\d+}})/g;

    const results = [];
    let lastIndex = 0;
    let match;

    while ((match = blockRegex.exec(raw)) !== null) {
      // Catch any text between matches (NAKED TEXT)
      const naked = raw.slice(lastIndex, match.index).trim();
      if (naked) results.push({ type: 'NAKED', content: naked });

      if (match[1]) results.push({ type: 'FILE', content: match[1] });
      else if (match[2]) results.push({ type: 'TEXT_BLOCK', content: match[2] });
      else if (match[3]) results.push({ type: 'HEADLINE', content: match[3] });
      else if (match[4]) results.push({ type: 'FOOTNOTE', content: match[4] });

      lastIndex = blockRegex.lastIndex;
    }

    const remaining = raw.slice(lastIndex).trim();
    if (remaining) results.push({ type: 'NAKED', content: remaining });

    return results;
  };

  const renderLines = (content: string) => {
    const blocks = parseBlocks(content);

    return blocks.map((block, bIdx) => {
      switch (block.type) {
        case 'FILE':
          return (
            <div key={bIdx} className="mt-8 mb-4 border-b-2 border-indigo-200 pb-1">
              <span className="bg-indigo-600 text-white px-2 py-0.5 text-[10px] font-bold uppercase rounded">
                {block.content.match(/FILE_START: (.*?) >>>>/)?.[1]}
              </span>
            </div>
          );

        case 'HEADLINE':
          const hMatch = block.content.match(/{{level\s*(\d+)}}([\s\S]*?){{-level\s*\1}}/);
          if (!hMatch) return null;
          const hLevel = parseInt(hMatch[1]);
          return (
            <div key={bIdx} className="my-2 flex items-center gap-2">
              <span className="text-[9px] font-bold text-slate-300">L{hLevel}</span>
              <div className={`${getStyleForLevel(hLevel)} px-3 py-1 rounded shadow-sm inline-block`}>
                {renderContentWithFootnotes(hMatch[2])}
              </div>
            </div>
          );

        case 'TEXT_BLOCK':
          const innerContent = block.content.replace(/{{-?text_level}}/g, '').trim();
          // Find internal level tags
          const innerMatches = Array.from(innerContent.matchAll(/{{level\s*(\d+)}}([\s\S]*?){{-level\s*\1}}/g));

          return (
            <div key={bIdx} className="my-2 p-2 bg-yellow-50/30 border border-yellow-100 rounded-lg shadow-inner">
              <div className="text-[8px] font-bold text-yellow-500 mb-1 tracking-widest">TEXT_LEVEL CONTAINER</div>
              {innerMatches.length > 0 ? innerMatches.map((m, mIdx) => {
                const level = parseInt(m[1]);
                return (
                  <div key={mIdx} className="flex gap-2 mb-1 last:mb-0">
                    <span className="text-[8px] font-bold text-slate-300 w-4">L{level}</span>
                    <div className={`${getStyleForLevel(level)} px-2 py-0.5 rounded-sm flex-1`}>
                      {renderContentWithFootnotes(m[2])}
                    </div>
                  </div>
                );
              }) : (
                <div className="p-2 bg-red-100 text-red-700 text-xs rounded border border-red-200 flex flex-col gap-1">
                  <span className="font-bold uppercase text-[9px]">Critical Error: Naked content inside text_level</span>
                  <p>{innerContent}</p>
                </div>
              )}
            </div>
          );

        case 'FOOTNOTE':
          const fMatch = block.content.match(/{{footnote\s*(\d+)}}([\s\S]*?){{-footnote\s*\d+}}/);
          if (!fMatch) return null;
          return (
            <div key={bIdx} className="mt-4 pt-2 border-t border-slate-100 italic text-xs text-purple-700 bg-purple-50/50 p-2 rounded">
              <span className="font-bold mr-2">FN {fMatch[1]}:</span>
              {renderContentWithFootnotes(fMatch[2])}
            </div>
          );

        case 'NAKED':
          return (
            <div key={bIdx} className="my-1 p-2 bg-red-600 text-white rounded text-xs flex flex-col shadow-lg border-2 border-red-900 animate-pulse">
              <span className="font-black uppercase text-[10px] mb-1">FATAL ERROR: NAKED TEXT (UNTAGGED)</span>
              <p className="font-mono bg-red-900/50 p-1 rounded">{block.content}</p>
            </div>
          );

        default: return null;
      }
    });
  };

  if (translatedText) {
    return (
      <div className="flex flex-row h-[750px] border border-slate-300 rounded-xl overflow-hidden bg-slate-50 shadow-2xl">
        <div className="flex-1 border-r border-slate-200 flex flex-col min-w-0 bg-white">
          <div className="bg-slate-800 text-white px-4 py-2 text-[10px] font-black uppercase tracking-widest">ORIGINAL SOURCE</div>
          <div className="flex-1 overflow-auto p-6 font-mono text-sm leading-relaxed">{renderLines(text)}</div>
        </div>
        <div className="flex-1 flex flex-col min-w-0 bg-indigo-50/30">
          <div className="bg-indigo-600 text-white px-4 py-2 text-[10px] font-black uppercase tracking-widest">TRANSLATION PREVIEW</div>
          <div className="flex-1 overflow-auto p-6 font-mono text-sm leading-relaxed">{renderLines(translatedText)}</div>
        </div>
      </div>
    );
  }

  return (
    <div className="font-mono text-sm bg-white p-8 rounded-xl overflow-auto max-h-[800px] border border-slate-300 shadow-2xl leading-relaxed">
      {renderLines(text)}
    </div>
  );
};

export default ResultViewer;
